#!/usr/bin/env python3
import sys

def snappy_decompress(src: bytes) -> bytes:
    """Pure-Python Snappy block decompression algorithm."""
    try:
        pos = 0
        dec_len = 0
        shift = 0
        while True:
            if pos >= len(src):
                return b""
            b = src[pos]
            pos += 1
            dec_len |= (b & 0x7f) << shift
            if not (b & 0x80):
                break
            shift += 7
            if shift >= 35:
                return b""
                
        out = bytearray()
        src_len = len(src)
        
        while pos < src_len:
            tag = src[pos]
            pos += 1
            tag_type = tag & 0x03
            
            if tag_type == 0x00:
                # Literal
                len_bits = tag >> 2
                if len_bits < 60:
                    lit_len = len_bits + 1
                elif len_bits == 60:
                    if pos + 1 > src_len: break
                    lit_len = src[pos] + 1
                    pos += 1
                elif len_bits == 61:
                    if pos + 2 > src_len: break
                    lit_len = int.from_bytes(src[pos:pos+2], 'little') + 1
                    pos += 2
                elif len_bits == 62:
                    if pos + 3 > src_len: break
                    lit_len = int.from_bytes(src[pos:pos+3], 'little') + 1
                    pos += 3
                else: # 63
                    if pos + 4 > src_len: break
                    lit_len = int.from_bytes(src[pos:pos+4], 'little') + 1
                    pos += 4
                    
                if pos + lit_len > src_len:
                    break
                out.extend(src[pos:pos+lit_len])
                pos += lit_len
            else:
                # Copy
                if tag_type == 0x01:
                    # Copy with 1-byte offset
                    lit_len = 3 + ((tag >> 2) & 0x07)
                    if pos >= src_len: break
                    offset = ((tag & 0xe0) << 3) | src[pos]
                    pos += 1
                elif tag_type == 0x02:
                    # Copy with 2-byte offset
                    lit_len = 1 + (tag >> 2)
                    if pos + 2 > src_len: break
                    offset = int.from_bytes(src[pos:pos+2], 'little')
                    pos += 2
                else: # 0x03
                    # Copy with 4-byte offset
                    lit_len = 1 + (tag >> 2)
                    if pos + 4 > src_len: break
                    offset = int.from_bytes(src[pos:pos+4], 'little')
                    pos += 4
                    
                if offset == 0 or offset > len(out):
                    break
                
                for _ in range(lit_len):
                    out.append(out[-offset])
                    
        return bytes(out)
    except Exception:
        return b""

